import proto from '@/utils/sdkapi_pb.js'

export function useAlarmClear(store) {
  // 发送清除报警命令
  const sendClearAlarm = (code) => {
    const request = new proto.Request()
    request.setCommand(proto.Command.CMD_CLEAR_ALARM)

    if (code) {
      const paramData = request.addParamData()
      // paramData.setKey('alarm_code')
      paramData.setKey('alarm_id')
      // 如果是数组，转为逗号分隔的字符串
      const codeStr = Array.isArray(code) ? code.join(',') : code.toString()
      paramData.setVal(codeStr)
    }

    const data = request.serializeBinary()
    store.websocketSendData({ data })
  }

  return {
    sendClearAlarm
  }
}
