<template>
  <div class="g-page-container">
    <div class="g-table">
      <!-- 表头 -->
      <div class="cell flex-space-between header">
        <!-- <div class="check">
          <el-checkbox
            :model-value="allChecked"
            @update:model-value="allCheckedChange"
            label=""
            size="small"
          />
        </div> -->
        <div
          v-for="(label, index) in labels"
          :key="index"
          class="name bg"
          :class="label.class"
        >
          {{ label.text }}
        </div>
        <div class="name bg refresh" @click="handleBatchClear">全部清除</div>
      </div>

      <!-- 数据行 -->
      <div
        class="cell flex-space-between"
        v-for="(item, index) in paginatedData"
        :key="index"
        :class="{ checked: item.checked }"
      >
        <!-- <div class="check">
          <el-checkbox
            :model-value="item.checked"
            @update:model-value="(val) => checkedChange(item, val)"
            label=""
            size="small"
          />
        </div> -->
        <div class="name code">{{ item.code }}</div>
        <div class="name timestamp">{{ formatTimestamp(item.timestamp) }}</div>
        <!-- <div class="name main-module">{{ item.mainModule }}</div>
        <div class="name sub-module">{{ item.subModule }}</div> -->
        <div class="name level">{{ item.level }}</div>
        <div class="name node-name">{{ item.nodeName }}</div>
        <div class="name data">{{ item.data }}</div>
        <div
          class="name refresh hidden-clear"
          @click.stop="handleSingleClear(item)"
        >
          清除
        </div>
      </div>
    </div>
    <pagination :total="tableData.length" @change="handlePageChange" />
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useSortData } from '@/hooks/useSortData'
import { useCheckbox } from '@/hooks/useCheckbox.js'
import { useAlarmClear } from '@/hooks/useAlarmClear'
// import { ElMessage } from 'element-plus'

import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

// store相关
const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)
const { sendClearAlarm } = useAlarmClear(store)

// 表头配置
const labels = [
  { text: '报警ID', class: 'code' },
  { text: '时间', class: 'timestamp' },
  // { text: '主模块', class: 'main-module' },
  // { text: '副模块', class: 'sub-module' },
  { text: '等级', class: 'level' },
  { text: '模块', class: 'node-name' },
  { text: '描述', class: 'data' }
]

// 获取报警数据，兼容13和61命令
const alarmData = computed(() => {
  if (!received.value?.statusData?.alarmDataList)
    return [
      {
        data: '暂无报警'
      }
    ]
  return received.value.statusData.alarmDataList
})

const sortedAlarmData = useSortData(alarmData, {
  key: 'code',
  type: 'number',
  order: 'asc'
}).sortedData

// 勾选框相关
const {
  tableData,
  // allChecked,
  // allCheckedChange,
  // checkedChange,
  clearChecked
  // getCheckedItems
} = useCheckbox(sortedAlarmData)

// 分页相关
const pageSize = ref(10)
const currentPage = ref(1)

// 分页数据
const paginatedData = computed(() => {
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return tableData.value.slice(start, end)
})

// 分页处理
const handlePageChange = (val) => {
  currentPage.value = val.page
  pageSize.value = val.size
  clearChecked()
}

// 单个清除处理-用id
// const handleSingleClear = (item) => {
//   if (item.id) {
//     sendClearAlarm(item.id)
//   }
// }

// 多个清除处理-统一all
const handleBatchClear = () => {
  // const checkedItems = getCheckedItems()
  // if (checkedItems.length === 0) {
  //   ElMessage({
  //     message: '请选择需要清除的报警',
  //     type: 'warning'
  //   })
  //   return
  // }
  // const ids = checkedItems.map((item) => item.id)
  // sendClearAlarm(ids)
  sendClearAlarm('all')
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('alarm')
    }
  },
  { immediate: true }
)
</script>

<style lang="less" scoped>
.hidden-clear {
  visibility: hidden; // 元素不可见，但占位保留
  pointer-events: none;
}

.name {
  &.code,
  // &.main-module,
  // &.sub-module,
  &.level,
  &.node-name {
    width: 9rem;
  }
  &.timestamp,
  &.data {
    width: 13rem;
  }
  &.refresh {
    width: 5rem;
  }
}
</style>
